VALUES
  ('judicial-cf446b4c-moex-00074', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列何者非民法第767條規定之物上請求權類型？', '["所有物返還請求權", "所有物賠償請求權", "所有權妨害排除請求權", "所有權妨害預防請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00075', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲為A地之所有人，乙為B地之所有人，A地與B地均為私用土地。甲在A地種植蘋果樹，蘋 果成熟後自落於B地。關於該自落於B地之蘋果所有權之歸屬，下列敘述何者正確?', '["推定屬於乙所有", "視為屬於乙所有", "屬於甲單獨所有", "屬於甲與乙共有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00076', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '抵押人得就抵押物設定數個普通抵押權，而於抵押物賣得之價金，除法律另有規定外，按各抵押 權成立之次序分配之。此次序亦係一種權利，一般稱之為次序權。下列何種次序權之處分，除抵 押權人之意思或相對人之合意外，另須經其他利害關係人同意後，始得為之？', '["為特定抵押權人之利益，讓與其抵押權之次序", "為特定後次序抵押權人之利益，拋棄其抵押權之次序", "為全體後次序抵押權人之利益，拋棄其抵押權之次序", "同一抵押物上之數抵押權人，就其抵押權之次序互換 20320 20420"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00077', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲以其所有之 A 地設定普通抵押權於乙，用以擔保其對乙所負借款債務之履行。關於甲於 A 地 設定抵押權後之權利，下列敘述何者錯誤？', '["甲得移轉A地所有權於第三人", "甲得以A地設定後次序之抵押權於第三人", "甲得將A地出租於第三人", "甲得聲請法院拍賣抵押之A地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00078', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲有經登記之A地，遭好友乙惡意占有並建B屋居住達18年，經甲發現後向法院訴請拆屋還地， 經乙求情後，甲撤回起訴，乙卻繼續占有 A 地經 3 年不願返還，甲無奈再次向法院訴請拆屋還 地。下列敘述何者正確？', '["乙公然和平繼續占有A地期間，受占有保護規定而成為有權占有", "乙得請求登記為A地所有人", "乙得請求登記為A地地上權人", "乙得請求登記為A地不動產役權人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00079', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列何者無過失時，亦應負損害賠償責任？', '["判決離婚時無過失之一方", "婚姻撤銷時無過失之一方", "善意且無過失之重婚者", "婚約解除時無過失之一方"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00080', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲、乙為兄弟，均已喪妻。甲有丙、丁二子，均尚未成年，乙有一女戊。乙擬收養5歲之丁。甲 代理丁與乙於民國111年2月1日合意丁被乙收養，於同年3月1日在公證人處完成書面契約， 同年4月1日向地方法院提出聲請，法院認可收養之裁定於同年10月1日確定。依民法規定， 乙、丁之收養契約何時生效？', '["民國111年2月1日", "民國111年3月1日", "民國111年4月1日", "民國111年10月1日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00081', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲、乙為夫妻，有一成年之子丙，丁為甲之父。乙、丙、丁均不能維持生活又無謀生能力，甲有 扶養能力。何人得優先受甲扶養？', '["乙丙", "乙丁", "丙丁", "乙丙丁"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00082', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於遺產繼承人之敘述，何者正確？', '["甲、乙為夫妻，同時遇難死亡，若無第一順位繼承人，則甲之父母僅得繼承甲之遺產，乙之父 母僅得繼承乙之遺產", "父母離婚，父與他人再婚，喪失對於其原生子女遺產之繼承權", "本生父母對於已出養子女之遺產，因仍具血緣關係，享有繼承權", "繼父對於妻之前夫所生之子女，因已共居日久，所以具備法律上之親子關係，對該子女之遺產 有繼承權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00083', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '得知離家數年之庚死亡時，庚配偶戊以為自己是唯一繼承人。未料，竟有丁出面主張庚其實已與 他多年如同夫妻般共同生活。關於庚之遺產，下列敘述何者正確？', '["喪葬費用應由法定繼承人支出，以免影響到庚遺產之正確數額", "如庚生前繼續扶養丁，丁得經程序主張受酌給遺產", "戊得主張遺產酌給請求權", "丁有事實上配偶之地位，與戊各得分配二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
